media_attachments.description:
enum ConvertFlags {
        CV_CPY = 0x80, // copy
        CV_TRN = 0x40, // truncate
        CV_XTN = 0x20, // sign extension
        CV_X08 = 0x38, // sign extend i8
        CV_X16 = 0x30, // sign extend i16
        CV_MSK = 0x1F, // shift mask
};

// truncation is lossless if src u32 form is < cv_lo[dst] or > cv_hi[dst]
var cv_lo [8]u32 = {
0x00000080, 0x00008000, 0x80000000, 0, 0x00000080, 0x00008000, 0x80000000, 0,
};
var cv_hi [8]u32 = {
0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF, 0, 0xFFFFFF7F, 0xFFFF7FFF, 0x7FFFFFFF, 0,
};

var cv_op [64]u8 = {
        // Dst ->
        // U8      U16     U32        I8      I16     I32
        CV_CPY, CV_CPY, CV_CPY, 0, CV_TRN, CV_CPY, CV_CPY, 0, // U8   Src
        CV_TRN, CV_CPY, CV_CPY, 0, CV_TRN, CV_TRN, CV_CPY, 0, // U16   |
        CV_TRN, CV_TRN, CV_CPY, 0, CV_TRN, CV_TRN, CV_TRN, 0, // U32   v
        0,      0,      0,      0, 0,      0,      0,      0, 
        CV_TRN, CV_TRN, CV_TRN, 0, CV_CPY, CV_X08, CV_X08, 0, // I8
        CV_TRN, CV_TRN, CV_TRN, 0, CV_TRN, CV_CPY, CV_X16, 0, // I16
        CV_TRN, CV_TRN, CV_TRN, 0, CV_TRN, CV_TRN, CV_CPY, 0, // I32
        0,      0,      0,      0, 0,      0,      0,      0, 
};
